module RefModule(cnt,rst,clk);input rst,clk;
  output [3:0] cnt;
  reg [3:0] cnt;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if(rst==1) begin
      cnt<=4'b0;
    end
    else begin
      cnt<=cnt+1;
    end
  end
endmodule
